@import url('https://fonts.googleapis.com/css2?family=Funnel+Display:ital,wght@0,400;0,700;0,900;1,400;1,700;1,900&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Workbench:ital,wght@0,400;0,700;0,900;1,400;1,700;1,900&display=swap');

.theme-fandomdesktop-light {
    --theme-page-background-color: #eeeeee;
    --theme-page-background-color--secondary: #ffffff;
    --theme-page-text-color: #2b2d2b;
    --theme-page-accent-mix-color: #cceecc;
    --theme-community-header-color: #0f0f0f;
    --theme-link-color: #228822;
	--theme-accent-color: #338833;
    --theme-accent-label-color: #ffffff;
    --theme-border-color: #99aa99;
	--theme-sticky-nav-background-color: #6fa06f;
    --quote: #dde0dd;
    --bquote: #b5c5b5;
    --dot-dot: rgba(20, 38, 20, 0.05);
    --shadow: #d2d9d2;
}

.theme-fandomdesktop-dark {
    --theme-page-background-color: #111111;
    --theme-page-background-color--secondary: #222222;
    --theme-page-text-color: #eeeeee;
    --theme-page-accent-mix-color: #556655;
    --theme-community-header-color: #ffffff;
    --theme-link-color: #77ff77;
	--theme-accent-color: #88ff88;
    --theme-accent-label-color: #ffffff;
    --theme-border-color: #a7b0a7;
	--theme-sticky-nav-background-color: #123612;
    --quote: #465d46;
    --bquote: #667d66;
    --dot-dot: rgba(40, 58, 40, 0.2);
    --shadow: #111911;
}
html .resizable-container, .page {
  font-family: 'Funnel Display', Monospace;
}
.page__main h1, .page__main h2, .page__main h3, .page__main h4 {
  font-family: 'Workbench', Courier;
}
.main-container {
  background: var(--theme-page-background-color);
}
.lightblock {
  background: var(--theme-page-background-color);
  box-shadow: none;
}
.page-header {
  background: var(--quote);
  padding: 15px;
  font-weight: bold;
  box-shadow: 14px 14px 0 var(--theme-page-background-color);
}
.page__main h2, .page__main h3, .page__main h4 {
  font-weight: bold;
  text-align: center;
  background: var(--quote);
  border-top: none !important;
  border-right: none !important;
  border-left: none !important;
  border-bottom: 1px solid var(--theme-border-color);
  &:has(⚠) {
    background: var(--bquote);
  }
}
.page-content {
  text-align: justify;
  overflow: visible;
  animation: space 0.5s ease;
}
.page__main {
  background: var(--theme-page-background-color--secondary);
}
.styled-quote {
  background-color: var(--quote) !important;
  border-left: 10px solid var(--bquote) !important;
}
.light-logoblock {
  background-color: var(--quote) !important;
  border-left: 10px solid var(--bquote) !important;
}
.theme-fandomdesktop-dark .fandom-community-header,
.theme-fandomdesktop-light .fandom-community-header {
    background-image: linear-gradient(transparent, var(--theme-page-background-color--secondary));
    margin-bottom: -12.5px;
    padding: 1em 2em;
    font-family: 'Funnel Display', Monospace;
}
@keyframes space {
    0% {
      letter-spacing: -4px;
    }
    100% {
      letter-spacing: 0;
    }
}

.fandom-community-header__image img {
  opacity:0;
}

.fandom-community-header__image::before {
  content:'';
  background:url('https://static.wikia.nocookie.net/backrooms/images/8/84/Site-logo_vegetative.png/revision/latest?cb=20260617130636') no-repeat;
  margin:0.9rem 0 0rem 0rem;
  width:100px;
  height:100px;
  background-size:87px;
  position: absolute;
}
.parent {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    grid-template-rows: repeat(2, 1fr);
    gap: 8px;
}
.t {
    will-change: transform;
    transition-duration: 0.5s;
}
.t:hover {
    transform: scale(105%);
}
.div1 {
    grid-row: span 2 / span 2;
    grid-column-start: 2;
    grid-row-start: 1;
    background-image: url('https://static.wikia.nocookie.net/backrooms/images/b/b3/Binaries.png/revision/latest?cb=20260614055357') !important;
    filter: contrast(70%);
    color: #07151f;
    text-shadow: -2px -2px 0 #b7bfcc, 2px -2px 0 #b7bfcc, -2px  2px 0 #b7bfcc, 2px  2px 0 #b7bfcc;
    background-size: cover !important;
    will-change: transform;
    transition-duration: 0.5s;
}
.div1:hover {
    transform: scale(105%);
}
.div2 {
    grid-column-start: 3;
    grid-row-start: 1;
}

.div3 {
    grid-column-start: 3;
    grid-row-start: 2;
}

.div4 {
    grid-column-start: 1;
    grid-row-start: 1;
}

.div5 {
    grid-column-start: 1;
    grid-row-start: 2;
}
.right-rail-wrapper, .page__main, .lightblock, .styled-quote, .page-header, .page__main h2, .light-logoblock {
	background-image: linear-gradient(to top, var(--dot-dot), transparent);
	background-size: 100px 7px;
    border: 1px solid var(--theme-border-color);
}
.right-rail-wrapper {
    background: var(--theme-page-background-color);
}
.rail-module {
	background: none;
}
.cred {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  grid-template-rows: 1fr;
  grid-column-gap: 5px;
  grid-row-gap: 5px;
  text-align: left;
  border-bottom: 1px solid var(--theme-border-color);
}
.cred2 {
  padding: 15px 0;
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  grid-template-rows: 2fr;
  grid-column-gap: 5px;
  grid-row-gap: 5px;
  text-align: left;
  border-bottom: 1px solid var(--theme-border-color);
}
.bl1 { grid-area: 1 / 1 / 2 / 2; }
.bl2 { grid-area: 1 / 2 / 2 / 3; }

.bl3 { grid-area: 1 / 1 / 2 / 2; }
.bl4 { grid-area: 1 / 2 / 2 / 3; }
}}
